namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) });
        _notifications.Add(new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) });
        _notifications.Add(new NotificationItem { Id = _nextId++, Message = "New feature: dark mode is available.", Timestamp = DateTime.UtcNow.AddMinutes(-2) });
    }

    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications.Where(n => n.Id > lastSeenId).ToList();
            return Task.FromResult(newer);
        }
    }

    public void SimulateNewNotification()
    {
        lock (_lock)
        {
            // Randomly generate a new notification ~30% of the time
            if (Random.Shared.Next(100) < 30)
            {
                var messages = new[]
                {
                    "Someone liked your post.",
                    "You have a new follower.",
                    "Reminder: meeting in 15 minutes.",
                    "Your report is ready to download.",
                    "System maintenance scheduled tonight."
                };

                _notifications.Add(new NotificationItem
                {
                    Id = _nextId++,
                    Message = messages[Random.Shared.Next(messages.Length)],
                    Timestamp = DateTime.UtcNow
                });
            }
        }
    }
}

