 @page "/notifications"
 @rendermode InteractiveServer
 @using NotificationsApp.Services
 @inject NotificationService NotificationService
 @implements IDisposable

 <PageTitle>Notifications</PageTitle>

 <h1>Notifications <span class="badge bg-primary">@(Items.Count ?? 0)</span></h1>

 @if (Notifications is null)
 {
     <p><em>Loading...</em></p>
 }
 else if (Items.Count == 0)
 {
     <p>No notifications yet.</p>
 }
 else
 {
     <ul class="list-group">
         @foreach (var notification in Items.OrderByDescending(n => n.Timestamp))
         {
             <li class="list-group-item">
                 <strong>@notification.Message</strong>
                 <small class="text-muted ms-2">@notification.Timestamp.ToString("HH:mm:ss")</small>
             </li>
         }
     </ul>
 }

 @code {
     private CancellationTokenSource? _cts;

     [PersistentState]
     public List<NotificationItem>? Notifications { get; set; }

     protected override async Task OnInitializedAsync()
     {
         // Only fetch if not already restored from prerender state
         Items ??= await NotificationService.GetNotificationsAsync();
     }

     protected override void OnAfterRender(bool firstRender)
     {
         if (firstRender)
         {
             // OnAfterRender never runs during prerender — safe to start polling
             _cts = new CancellationTokenSource();
             _ = PollForNotificationsAsync(_cts.Token);
         }
     }

     private async Task PollForNotificationsAsync(CancellationToken ct)
     {
         var lastSeenId = Items.MaxBy(n => n.Id)?.Id ?? 0;

         while (!ct.IsCancellationRequested)
         {
             await Task.Delay(TimeSpan.FromSeconds(5), ct);

             // Simulate new notifications arriving in the service
             NotificationService.SimulateNewNotification();

             var newItems = await NotificationService.GetNotificationsSinceAsync(lastSeenId);
             if (newItems.Count > 0)
             {
                 Items ??= new();
                 Items.AddRange(newItems);
                 lastSeenId = newItems.Max(n => n.Id);
                 await InvokeAsync(StateHasChanged);
             }
         }
     }

     public void Dispose()
     {
         _cts?.Cancel();
         _cts?.Dispose();
     }
 }

